if not doc.custom_member_id:
    count = frappe.db.count("Customer")
    last = frappe.db.get_value("Customer", {}, "custom_member_id", order_by="creation desc")
    num = 1
    if last:
        try:
            last_num = int(last.split("-")[-1])
            num = max(count + 1, last_num + 1)
        except (ValueError, IndexError):
            num = count + 1
    else:
        num = count + 1
    doc.custom_member_id = f"MEM-{num:05d}"
